import mathdef calculate_angle(x1, y1, x2, y2):    dx = x2 - x1    dy = y2 - y1    return math.degrees(math.atan2(dy, dx))def find_turning_points_old(xs, ys, angle_threshold=90.0):    turning_points = []    for i in range(1, len(xs) - 1):        angle = calculate_angle(xs[i - 1], ys[i - 1], xs[i + 1], ys[i + 1])        if abs(angle) > angle_threshold:            turning_points.append((xs[i], ys[i]))    return turning_pointsdef find_turning_points(xs, ys, angle_threshold=90.0):    turning_points = []    for i in range(1, len(xs) - 1):        angle1 = calculate_angle(xs[i - 1], ys[i - 1], xs[i], ys[i])        angle2 = calculate_angle(xs[i], ys[i], xs[i + 1], ys[i + 1])        angle_change = abs(angle2 - angle1)        if angle_change > angle_threshold:            turning_points.append((xs[i], ys[i]))    return turning_pointsdef check_turning_points(xs,ys):        turning_points = find_turning_points(xs, ys)    if turning_points:        """        print("there is a turning points：")        for point in turning_points:            print(point)        """        return True    else:        # print("no turning points。")        return False    if __name__ == '__main__':    pass